108	function deriveSignals(world, now) {
109	  const nowMs = Date.parse(now);
110	  const fired = [];
111	
112	  const overdueInvoice = (world.invoices || []).find(
113	    (invoice) =>
114	      invoice.status !== "paid" &&
115	      Date.parse(invoice.dueDate) < nowMs &&
116	      invoice.amountCents >= 25_000 * 100
117	  );
118	  if (overdueInvoice) {
119	    fired.push({
120	      category: "invoice",
121	      name: "Overdue invoice",
122	      detail: `Invoice ${overdueInvoice.invoiceId} for $${Math.round(overdueInvoice.amountCents / 100).toLocaleString("en-US")} past due.`
123	    });
124	  }
125	
126	  const lateShipment = (world.shipments || []).find((shipment) => !shipment.deliveredDate && Date.parse(shipment.slaDate) < nowMs);
127	  if (lateShipment) {
128	    fired.push({
129	      category: "shipment",
130	      name: "Delayed shipment",
131	      detail: `Shipment ${lateShipment.shipmentId} past its delivery commitment.`
132	    });
133	  }
134	
135	  const openRegulatoryFlag = (world.regulatoryFlags || []).find((flag) => flag.status === "open");
136	  if (openRegulatoryFlag) {
137	    fired.push({
138	      category: "regulatory",
139	      name: "Regulatory hold",
140	      detail: `Open ${openRegulatoryFlag.type} regulatory flag (${openRegulatoryFlag.flagId}).`
141	    });
142	  }
143	
144	  const escalatedSupport = (world.supportCases || []).find(
145	    (supportCase) =>
146	      supportCase.status === "open" && ["high", "critical"].includes(String(supportCase.severity || "").toLowerCase())
147	  );
148	  if (escalatedSupport) {
149	    fired.push({
150	      category: "support",
151	      name: "Escalated support",
152	      detail: `Support case ${escalatedSupport.caseId} at ${escalatedSupport.severity} severity.`
153	    });
154	  }
155	
156	  const usage = world.usage || {};
157	  if (
158	    typeof usage.priorPeriodUnits === "number" &&
159	    typeof usage.currentPeriodUnits === "number" &&
160	    usage.priorPeriodUnits > 0 &&
161	    usage.currentPeriodUnits <= usage.priorPeriodUnits * 0.7
162	  ) {
163	    const dropPct = Math.round((1 - usage.currentPeriodUnits / usage.priorPeriodUnits) * 100);
164	    fired.push({
165	      category: "usage",
166	      name: "Usage decline",
167	      detail: `Usage down ${dropPct}% period-over-period.`
168	    });
169	  }
170	
171	  return SIGNALS.filter((signal) => fired.some((item) => item.category === signal.category)).map((signal) => ({
172	    ...signal,
173	    detail: fired.find((item) => item.category === signal.category)?.detail || ""
174	  }));
175	}
