177	function deriveOwners(signals) {
178	  const owners = new Set();
179	  for (const signal of signals) {
180	    owners.add(OWNER_FOR_CATEGORY[signal.category]);
181	  }
182	  return OWNER_ORDER.filter((owner) => owners.has(owner));
183	}
