191	function buildCustomerMessage({ qualifies, owners, signals }) {
192	  if (!qualifies) {
193	    return "We are continuing standard monitoring and no escalation is required at this time. We will only reach out if the situation changes.";
194	  }
195	
196	  const signalNames = signals.map((signal) => signal.name.toLowerCase()).join(", ");
197	  const ownerText = owners.join(", ");
198	  return `We have opened a coordinated review across ${ownerText} because there are active issues involving ${signalNames}. Our teams are working through the recovery plan and will share customer-safe updates as actions are confirmed.`;
199	}
