201	function buildAuditBody({ qualifies, owners, signals, nextStep }) {
202	  if (!qualifies) {
203	    return "Standard monitoring update published to the customer portal.";
204	  }
205	
206	  const signalNames = signals.map((signal) => signal.name.toLowerCase()).join(", ");
207	  return `Customer-visible escalation update published for ${owners.join(", ")}. Active signals: ${signalNames}. Next step: ${nextStep}.`;
208	}
